class Solution {
    public int maxAbsValExpr(int[] arr1, int[] arr2) {
        int n = arr1.length;
        int[][] points = new int[n][3];
        for (int i = 0; i < n; i++) {
            points[i] = new int[] {arr1[i] + arr2[i], arr1[i] - arr2[i], i};
        }

        Arrays.sort(points, (a, b) -> a[0] - b[0]);
        int max = Integer.MIN_VALUE;
        int curMax = Integer.MIN_VALUE;
        for (int[] p : points) {
            max = Math.max(max, p[0] - curMax);
            curMax = Math.max(curMax, p[1] + p[2]);
        }

        Arrays.sort(points, (a, b) -> a[1] - b[1]);
        curMax = Integer.MIN_VALUE;
        for (int[] p : points) {
            max = Math.max(max, p[1] - curMax);
            curMax = Math.max(curMax, p[0] + p[2]);
        }

        Arrays.sort(points, (a, b) -> a[2] - b[2]);
        curMax = Integer.MIN_VALUE;
        for (int[] p : points) {
            max = Math.max(max, p[2] - curMax);
            curMax = Math.max(curMax, p[0] + p[1]);
        }

        return max;
    }
}
